using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new OrderService();

    // --- CreateOrder: happy-path ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(45.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = MakeItems(1);

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCustomerId()
    {
        var items = MakeItems(1);

        var order = _sut.CreateOrder("cust-42", items);

        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;

        var order = _sut.CreateOrder("cust-1", MakeItems(1));

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        var items = MakeItems(3);

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(3, order.Items.Count);
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, MakeItems(1)));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    // --- CreateOrder: total calculation edge cases ---

    [TestMethod]
    public void CreateOrder_SingleItemQuantityOne_TotalEqualsPrice()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Solo", Price = 7.99m, Quantity = 1 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(7.99m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ZeroQuantityItem_ContributesZeroToTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Free", Price = 50.00m, Quantity = 0 },
            new() { ProductName = "Paid", Price = 10.00m, Quantity = 1 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(10.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ZeroPriceItem_ContributesZeroToTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Freebie", Price = 0m, Quantity = 5 },
            new() { ProductName = "Paid", Price = 3.00m, Quantity = 2 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(6.00m, order.Total);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var order = _sut.CreateOrder("cust-1", MakeItems(1));

        var retrieved = _sut.GetOrder(order.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(order.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreations_ReturnsCorrectOrder()
    {
        var order1 = _sut.CreateOrder("cust-1", MakeItems(1));
        var order2 = _sut.CreateOrder("cust-2", MakeItems(2));

        var retrieved = _sut.GetOrder(order2.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual("cust-2", retrieved.CustomerId);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllTheirOrders()
    {
        _sut.CreateOrder("cust-A", MakeItems(1));
        _sut.CreateOrder("cust-A", MakeItems(1));
        _sut.CreateOrder("cust-B", MakeItems(1));

        var orders = _sut.GetOrdersByCustomer("cust-A");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        _sut.CreateOrder("cust-A", MakeItems(1));

        var orders = _sut.GetOrdersByCustomer("cust-Z");

        Assert.AreEqual(0, orders.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsReadOnlyList()
    {
        _sut.CreateOrder("cust-A", MakeItems(1));

        var orders = _sut.GetOrdersByCustomer("cust-A");

        Assert.IsInstanceOfType<IReadOnlyList<Order>>(orders);
    }

    // --- helpers ---

    private static List<OrderItem> MakeItems(int count) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product-{i}",
                Price = 5.00m * i,
                Quantity = i
            })
            .ToList();
}

